 12	// RunsStateProvider is the optional sub-interface a StateProvider may
 13	// implement to back the runs/run queries.
 14	// Kept separate from StateProvider so test stubs that don't need runs
 15	// continue to compile.
 16	type RunsStateProvider interface {
 17		GetRunsGraphQL(projectID string, filter RunFilter) []*Run
 18		GetRunGraphQL(id string) (*Run, bool)
 19	}
