 39	// Runs is the resolver for the runs field.
 40	func (r *queryResolver) Runs(ctx context.Context, projectID *string, layer *RunLayer, beadID *string, status *string, harness *string, first *int, after *string) (*RunConnection, error) {
 41		provider, ok := r.State.(RunsStateProvider)
 42		if !ok {
 43			return emptyRunConnection(), nil
 44		}
 45		pid := ""
 46		if projectID != nil {
 47			pid = *projectID
 48		}
 49		filter := RunFilter{Layer: layer}
 50		if beadID != nil {
 51			filter.BeadID = *beadID
 52		}
 53		if status != nil {
 54			filter.Status = *status
 55		}
 56		if harness != nil {
 57			filter.Harness = *harness
 58		}
 59		all := provider.GetRunsGraphQL(pid, filter)
 60		return runConnectionFrom(all, first, after), nil
 61	}
