 63	// Run is the resolver for the run field.
 64	func (r *queryResolver) Run(ctx context.Context, id string) (*Run, error) {
 65		provider, ok := r.State.(RunsStateProvider)
 66		if !ok {
 67			return nil, nil
 68		}
 69		wd := r.workingDir(ctx)
 70		if wd == "" {
 71			return nil, nil
 72		}
 73		projectID, ok := r.projectIDForWorkingDir(wd)
 74		if !ok {
 75			return nil, nil
 76		}
 77		run, ok := provider.GetRunGraphQL(id)
 78		if !ok {
 79			return nil, nil
 80		}
 81		if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) != projectID {
 82			return nil, nil
 83		}
 84		r.recordRunDetailView(ctx, run)
 85		return run, nil
 86	}
