 88	func (r *queryResolver) projectIDForWorkingDir(workingDir string) (string, bool) {
 89		if r.State == nil || workingDir == "" {
 90			return "", false
 91		}
 92		for _, proj := range r.State.GetProjectSnapshots(false) {
 93			if proj.Path == workingDir {
 94				return proj.ID, true
 95			}
 96		}
 97		return "", false
 98	}
