100	// recordRunDetailView appends the canonical run_detail_view bead audit event
101	// the first time a project-scoped run detail is resolved for a specific run.
102	// Duplicate loads of the same run id are ignored, but distinct runs on the
103	// same bead remain auditable.
104	func (r *queryResolver) recordRunDetailView(ctx context.Context, run *Run) {
105		if run == nil || run.BeadID == nil || strings.TrimSpace(*run.BeadID) == "" {
106			return
107		}
108		if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) == "" {
109			return
110		}
111		wd := r.workingDir(ctx)
112		if wd == "" {
113			return
114		}
115		if projectID, ok := r.projectIDForWorkingDir(wd); !ok || projectID != strings.TrimSpace(*run.ProjectID) {
116			return
117		}
118	
119		store := bead.NewStore(filepath.Join(wd, ".ddx"))
120		if existing, err := store.EventsByKind(*run.BeadID, runDetailViewEventKind); err == nil {
121			for _, ev := range existing {
122				if strings.Contains(ev.Body, "run_id="+run.ID) {
123					return
124				}
125			}
126		}
127	
128		identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
129		if httpReq := httpRequestFromContext(ctx); httpReq != nil {
130			identity = operatorPromptIdentity(httpReq)
131		}
132		body := fmt.Sprintf(
133			"project_id=%s run_id=%s layer=%s visibility=project_membership",
134			*run.ProjectID,
135			run.ID,
136			run.Layer,
137		)
138		_ = store.AppendEvent(*run.BeadID, bead.BeadEvent{
139			Kind:    runDetailViewEventKind,
140			Summary: "run detail viewed",
141			Body:    body,
142			Actor:   identity.actor,
143			Source:  "graphql:run",
144		})
145	}
