147	// RunToolCalls is the resolver for the runToolCalls field. Returns the
148	// normalized tool-call entries persisted at drain time, paginated by
149	// sequence. Returns an empty connection (not an error) for unknown ids or
150	// when the backing state provider does not implement RunDetailStateProvider.
151	func (r *queryResolver) RunToolCalls(ctx context.Context, id string, first *int, after *string) (*RunToolCallConnection, error) {
152		provider, ok := r.State.(RunDetailStateProvider)
153		if !ok {
154			return emptyRunToolCallConnection(), nil
155		}
156		calls := provider.GetRunToolCallsGraphQL(id)
157		return runToolCallConnectionFrom(calls, first, after), nil
158	}
