160	// RunBundleFile is the resolver for the runBundleFile field. Returns nil
161	// (not an error) when the path fails canonical-path / whitelist checks or
162	// the file is not present — the GraphQL response treats nil as 404.
163	func (r *queryResolver) RunBundleFile(ctx context.Context, id string, path string) (*RunBundleFileContent, error) {
164		provider, ok := r.State.(RunDetailStateProvider)
165		if !ok {
166			return nil, nil
167		}
168		out, ok := provider.GetRunBundleFileGraphQL(id, path)
169		if !ok {
170			return nil, nil
171		}
172		return out, nil
173	}
